CREATE DATABASE SCOPED CREDENTIAL cred_awstorageabhi
WITH IDENTITY = 'Managed Identit


CREATE EXTERNAL DATA SOURCE silver_data_source
WITH (
    LOCATION = 'https://awstorageabhi.dfs.core.windows.net/silver',
    CREDENTIAL = cred_awstorageabhi
);


CREATE EXTERNAL DATA SOURCE gold_data_source
WITH (
    LOCATION = 'https://awstorageabhi.dfs.core.windows.net/gold',
    CREDENTIAL = cred_awstorageabhi
);

CREATE EXTERNAL FILE FORMAT format_parquet
WITH (
    FORMAT_TYPE = PARQUET,
    DATA_COMPRESSION = 'org.apache.hadoop.io.compress.SnappyCodec'
);







CREATE EXTERNAL TABLE gold.EXTsales
WITH (
    LOCATION = 'EXTsales',
    DATA_SOURCE = gold_data_source,
    FILE_FORMAT = format_parquet
)
AS
SELECT *
FROM gold.Sales;





select * from gold.EXTsales;
